SELECT COUNT(DISTINCT tenant_id) 
FROM tenant_details 
WHERE service_level_agreement = 1;

SELECT AVG(wall_time) AS average_wall_time
FROM performance_metrics
WHERE normalized_performance > (SELECT threshold FROM alert_levels WHERE alert_level_id = 1);

SELECT optimization_date, description
FROM performance_optimizations
WHERE tenant_id = 0;

SELECT optimization_type_id, optimization_type_name, description, impact_description
FROM optimization_types
WHERE optimization_type_name = 'Code Optimization';

SELECT AVG(max_wall_time) AS average_wall_time
FROM service_levels
WHERE service_level_name = 'Gold';
